+func TestErrLoopBreak(t *testing.T) {
+	err := &ErrLoopBreak{Reason: "condition met"}
+	expected := "loop break: condition met"
+	if err.Error() != expected {
+		t.Errorf("expected %q, got %q", expected, err.Error())
+	}
