+			wantLen: 3,
+			wantErr: false,
+		},
+		{
+			name:    "[]string",
+			input:   []string{"x", "y"},
+			wantLen: 2,
+			wantErr: false,
+		},
+		{
+			name:    "[]int",
+			input:   []int{1, 2, 3, 4},
+			wantLen: 4,
+			wantErr: false,
+		},
+		{
