+			wantLen: 2,
+			wantErr: false,
+		},
+		{
+			name:    "comma-separated string",
+			input:   "a, b, c",
+			wantLen: 3,
+			wantErr: false,
+		},
+		{
+			name:    "unsupported type",
+			input:   42,
+			wantLen: 0,
+			wantErr: true,
+		},
+	}
